     1→import { EventEmitter } from 'node:events';
     2→import { mkdirSync } from 'node:fs';
     3→import { join, resolve } from 'node:path';
     4→import { homedir } from 'node:os';
     5→import { writeFileSync } from 'node:fs';
     6→import type { ServerConfig } from '../config/types.js';
     7→import type { TaskRecord, TaskStatus } from '../state/types.js';
     8→import type { ClaudeEvent, ExecutionResult, TaskInput } from '../claude/types.js';
     9→import { StateStore } from '../state/store.js';
    10→import { transition } from './state-machine.js';
    11→import { buildPrompt } from '../claude/prompt-builder.js';
    12→import { executeClaudeCode } from '../claude/executor.js';
    13→import { commitAndPush } from '../git/branch.js';
    14→import { createWorktree, removeWorktree, findGitRepo } from '../git/worktree.js';
    15→import { branchName } from '../git/branch.js';
    16→import { createDraftPr, buildPrTitle, buildPrBody } from '../git/pr.js';
    17→
    18→export class PipelineManager extends EventEmitter {
    19→  private store: StateStore;
    20→  private config: ServerConfig;
    21→  private activeCount = 0;
    22→  private queue: string[] = [];
    23→  private processing = false;
    24→
    25→  constructor(store: StateStore, config: ServerConfig) {
    26→    super();
    27→    this.store = store;
    28→    this.config = config;
    29→  }
    30→
    31→  submitTask(input: TaskInput): TaskRecord {
    32→    const existing = this.store.getTask(input.key);
    33→    if (existing && (existing.status === 'queued' || existing.status === 'in-progress')) {
    34→      throw new Error(`Task ${input.key} is already ${existing.status}`);
    35→    }
    36→
    37→    const task: TaskRecord = {
    38→      key: input.key,
    39→      summary: input.summary,
    40→      description: input.description,
    41→      acceptanceCriteria: input.acceptanceCriteria,
    42→      priority: input.priority,
    43→      issueType: input.issueType,
    44→      labels: input.labels,
    45→      comments: input.comments,
    46→      subtasks: input.subtasks,
    47→      linkedIssues: input.linkedIssues,
    48→      attachments: input.attachments,
    49→      assignee: input.assignee,
    50→      reporter: input.reporter,
    51→      components: input.components,
    52→      parentKey: input.parentKey,
    53→      jiraUrl: input.jiraUrl,
    54→      status: 'queued',
    55→      // Preserve branch name from previous attempt so we continue on the same branch
    56→      branchName: existing?.branchName,
    57→      createdAt: new Date().toISOString(),
    58→      updatedAt: new Date().toISOString(),
    59→    };
    60→
    61→    this.store.upsertTask(task);
    62→    this.store.flushSync();
    63→    this.queue.push(task.key);
    64→    this.emit('task-created', task);
    65→    setImmediate(() => this.processQueue());
    66→    return task;
    67→  }
    68→
    69→  retryTask(key: string): TaskRecord {
    70→    const task = this.store.getTask(key);
    71→    if (!task) throw new Error(`Task ${key} not found`);
    72→
    73→    const newStatus = transition(task.status, 'retry');
    74→    const oldStatus = task.status;
    75→    this.store.updateTaskStatus(key, newStatus, { errorMessage: undefined });
    76→    this.store.flushSync();
    77→    this.queue.push(key);
    78→    this.emit('task-status-changed', this.store.getTask(key)!, oldStatus);
    79→    setImmediate(() => this.processQueue());
    80→    return this.store.getTask(key)!;
    81→  }
    82→
    83→  private processQueue(): void {
    84→    if (this.processing) return;
    85→    this.processing = true;
    86→
    87→    try {
    88→      while (this.queue.length > 0 && this.activeCount < this.config.pipeline.concurrency) {
    89→        const key = this.queue.shift();
    90→        if (!key) break;
    91→        const task = this.store.getTask(key);
    92→        if (!task) continue;
    93→        this.runTask(key);
    94→      }
    95→    } finally {
    96→      this.processing = false;
    97→    }
    98→  }
    99→
   100→  private transitionTask(key: string, action: 'start' | 'complete' | 'fail', extra?: Partial<TaskRecord>): void {
   101→    const task = this.store.getTask(key);
   102→    if (!task) return;
   103→    const oldStatus = task.status;
   104→    const newStatus = transition(task.status, action);
   105→    this.store.updateTaskStatus(key, newStatus, extra);
   106→    this.store.flushSync();
   107→    const updated = this.store.getTask(key)!;
   108→    this.emit('task-status-changed', updated, oldStatus);
   109→    if (newStatus === 'completed' || newStatus === 'failed') {
   110→      this.emit('task-completed', updated);
   111→    }
   112→  }
   113→
   114→  private async runTask(key: string): Promise<void> {
   115→    const task = this.store.getTask(key)!;
   116→    const repoRoot = this.config.repoPath;
   117→
   118→    this.activeCount++;
   119→    console.log(`\n${'='.repeat(60)}`);
   120→    console.log(`[PIPELINE] Starting task: ${task.key} — ${task.summary} (${this.activeCount}/${this.config.pipeline.concurrency} active)`);
   121→    console.log(`[PIPELINE] Repo root: ${repoRoot}`);
   122→    console.log(`${'='.repeat(60)}`);
   123→    this.transitionTask(key, 'start', { startedAt: new Date().toISOString() });
   124→
   125→    const logsDir = this.config.logsDir ?? resolve(homedir(), '.jiranimo', 'logs');
   126→    mkdirSync(logsDir, { recursive: true });
   127→    const logPath = join(logsDir, `${key}-${Date.now()}.jsonl`);
   128→    const logLines: string[] = [];
   129→    let worktreePath: string | null = null;
   130→    let gitRepoPath: string | null = null;
   131→
   132→    try {
   133→      // 1. Find the git repo inside repoRoot
   134→      gitRepoPath = await findGitRepo(repoRoot);
   135→      if (!gitRepoPath) {
   136→        throw new Error(`No git repository found in ${repoRoot}`);
   137→      }
   138→      console.log(`[PIPELINE] Git repo: ${gitRepoPath}`);
   139→
   140→      // 2. Create a worktree for this task (isolated from user's working directory)
   141→      // Reuse existing branch name if this is a re-implementation, otherwise generate a new one
   142→      const branch = task.branchName ?? branchName(this.config.git.branchPrefix, task.key, task.summary);
   143→      worktreePath = await createWorktree(
   144→        gitRepoPath,
   145→        task.key,
   146→        branch,
   147→        this.config.git.defaultBaseBranch,
   148→        this.config.git.pushRemote,
   149→      );
   150→      console.log(`[PIPELINE] Worktree created: ${worktreePath}`);
   151→      console.log(`[PIPELINE] Branch: ${branch}`);
   152→      this.store.updateTaskStatus(key, 'in-progress', { branchName: branch });
   153→
   154→      // 3. Build prompt and run Claude in the worktree
   155→      const prompt = buildPrompt(task, this.config.claude.appendSystemPrompt);
   156→
   157→      console.log(`[PIPELINE] Prompt built (${prompt.length} chars)`);
   158→      console.log(`[PIPELINE] Spawning Claude Code in worktree...`);
   159→      console.log(`${'─'.repeat(60)}`);
   160→
   161→      const result: ExecutionResult = await executeClaudeCode({
   162→        prompt,
   163→        cwd: worktreePath,
   164→        config: this.config.claude,
   165→        timeoutMs: 30 * 60 * 1000,
   166→        onEvent: (event: ClaudeEvent) => {
   167→          logLines.push(JSON.stringify(event.raw));
   168→          this.emit('task-output', key, JSON.stringify(event.raw));
   169→          if (event.text) {
   170→            console.log(`[CLAUDE] ${event.text}`);
   171→          } else if (event.type === 'init' && event.sessionId) {
   172→            console.log(`[CLAUDE] Session started: ${event.sessionId}`);
   173→          } else if (event.type === 'result') {
   174→            console.log(`[CLAUDE] Result: ${event.isError ? 'ERROR' : 'SUCCESS'} — ${event.text?.slice(0, 200) || ''}`);
   175→          }
   176→        },
   177→        onOutput: (raw: string) => {
   178→          for (const line of raw.split('\n')) {
   179→            const trimmed = line.trim();
   180→            if (trimmed && !trimmed.startsWith('{')) {
   181→              console.log(`[CLAUDE RAW] ${trimmed}`);
   182→            }
   183→          }
   184→        },
   185→      });
   186→
   187→      console.log(`${'─'.repeat(60)}`);
   188→      console.log(`[PIPELINE] Claude finished — success: ${result.success}, cost: $${result.costUsd ?? 0}, duration: ${result.durationMs}ms`);
   189→      writeFileSync(logPath, logLines.join('\n'), 'utf-8');
   190→      console.log(`[PIPELINE] Logs saved to: ${logPath}`);
   191→
   192→      if (!result.success) {
   193→        throw new Error(result.resultText);
   194→      }
   195→
   196→      // 4. Commit and push from the worktree
   197→      await commitAndPush(
   198→        worktreePath,
   199→        branch,
   200→        task.key,
   201→        task.summary,
   202→        task.issueType,
   203→        task.jiraUrl,
   204→        this.config.git.pushRemote,
   205→      );
   206→      console.log(`[PIPELINE] Changes committed and pushed`);
   207→
   208→      // 5. Create a draft PR if configured
   209→      let prUrl: string | undefined;
   210→      let prNumber: number | undefined;
   211→      if (this.config.git.createDraftPr) {
   212→        try {
   213→          const pr = await createDraftPr({
   214→            cwd: worktreePath,
   215→            baseBranch: this.config.git.defaultBaseBranch,
   216→            headBranch: branch,
   217→            title: buildPrTitle(task.key, task.summary),
   218→            body: buildPrBody({
   219→              issueKey: task.key,
   220→              summary: task.summary,
   221→              description: task.description,
   222→              jiraUrl: task.jiraUrl,
   223→              resultText: result.resultText,
   224→              costUsd: result.costUsd,
   225→              durationMs: result.durationMs,
   226→            }),
   227→          });
   228→          prUrl = pr.url;
   229→          prNumber = pr.number;
   230→          console.log(`[PIPELINE] Draft PR created: ${prUrl}`);
   231→        } catch (err) {
   232→          console.warn(`[PIPELINE] PR creation failed (non-fatal): ${(err as Error).message}`);
   233→        }
   234→      }
   235→
   236→      this.transitionTask(key, 'complete', {
   237→        claudeSessionId: result.sessionId,
   238→        claudeCostUsd: result.costUsd,
   239→        claudeResultText: result.resultText,
   240→        prUrl,
   241→        prNumber,
   242→        logPath,
   243→        completedAt: new Date().toISOString(),
   244→      });
   245→      console.log(`[PIPELINE] ✓ Task ${key} completed successfully`);
   246→      console.log(`${'='.repeat(60)}\n`);
   247→    } catch (err) {
   248→      writeFileSync(logPath, logLines.join('\n'), 'utf-8');
   249→      console.error(`[PIPELINE] ✗ Task ${key} failed: ${(err as Error).message}`);
   250→      console.log(`[PIPELINE] Logs: ${logPath}`);
   251→      console.log(`${'='.repeat(60)}\n`);
   252→      this.transitionTask(key, 'fail', {
   253→        errorMessage: (err as Error).message,
   254→        logPath,
   255→      });
   256→    } finally {
   257→      // 5. Clean up worktree
   258→      if (worktreePath && gitRepoPath) {
   259→        try {
   260→          await removeWorktree(gitRepoPath, worktreePath);
   261→          console.log(`[PIPELINE] Worktree removed: ${worktreePath}`);
   262→        } catch (err) {
   263→          console.warn(`[PIPELINE] Failed to remove worktree: ${(err as Error).message}`);
   264→        }
   265→      }
   266→      this.activeCount--;
   267→      this.processQueue();
   268→    }
   269→  }
   270→}
