     1→import { EventEmitter } from 'node:events';
     2→import type { ClaudeEvent } from './types.js';
     3→
     4→export class OutputParser extends EventEmitter {
     5→  private buffer = '';
     6→
     7→  feed(chunk: string): void {
     8→    this.buffer += chunk;
     9→    const lines = this.buffer.split('\n');
    10→    // Keep the last incomplete line in the buffer
    11→    this.buffer = lines.pop() ?? '';
    12→
    13→    for (const line of lines) {
    14→      const trimmed = line.trim();
    15→      if (!trimmed) continue;
    16→      this.parseLine(trimmed);
    17→    }
    18→  }
    19→
    20→  flush(): void {
    21→    if (this.buffer.trim()) {
    22→      this.parseLine(this.buffer.trim());
    23→      this.buffer = '';
    24→    }
    25→  }
    26→
    27→  private parseLine(line: string): void {
    28→    let parsed: Record<string, unknown>;
    29→    try {
    30→      parsed = JSON.parse(line);
    31→    } catch {
    32→      // Skip malformed lines
    33→      this.emit('parse-error', line);
    34→      return;
    35→    }
    36→
    37→    const event = this.toClaudeEvent(parsed);
    38→    if (event) {
    39→      this.emit('event', event);
    40→      if (event.type === 'result') {
    41→        this.emit('result', event);
    42→      }
    43→    }
    44→  }
    45→
    46→  private toClaudeEvent(raw: Record<string, unknown>): ClaudeEvent | null {
    47→    const type = raw.type as string | undefined;
    48→
    49→    if (type === 'system') {
    50→      const sessionId = raw.session_id as string | undefined;
    51→      return { type: 'init', raw, sessionId };
    52→    }
    53→
    54→    if (type === 'assistant') {
    55→      const message = raw.message as Record<string, unknown> | undefined;
    56→      const content = message?.content;
    57→      let text: string | undefined;
    58→      if (Array.isArray(content)) {
    59→        text = content
    60→          .filter((c: Record<string, unknown>) => c.type === 'text')
    61→          .map((c: Record<string, unknown>) => c.text)
    62→          .join('');
    63→      }
    64→      return { type: 'message', raw, text };
    65→    }
    66→
    67→    if (type === 'result') {
    68→      const subtype = raw.subtype as string | undefined;
    69→      const isError = subtype === 'error_max_turns' || subtype === 'error';
    70→      const resultText = raw.result as string | undefined;
    71→      const costUsd = (raw.total_cost_usd ?? raw.cost_usd) as number | undefined;
    72→      const sessionId = raw.session_id as string | undefined;
    73→
    74→      return {
    75→        type: 'result',
    76→        raw,
    77→        text: resultText,
    78→        isError,
    79→        costUsd,
    80→        sessionId,
    81→      };
    82→    }
    83→
    84→    // Unknown event type — still emit it
    85→    return { type: 'message', raw };
    86→  }
    87→}
